CA,UACA,WACA,YACA,mBACA,qBACA,kBAGA,qCACA,yBAIA,sCACA,yBAIA,mCACA,yBASJ,wBACA,yBACA,kBACA,gBAGA,8BACI,kBACA,WAOJ,uBACA,cACA,gBACA,aACA,sBACA,WACA,cACA,gBACA,iBACA,0BACA,mBACA,0BAEI,2BACI,cAKR,+BACI,2BACA,oCACI,eACA,2BAEJ,qCACA,aACA,UACA,WACA,6BACA,2BAEA,qCACI,WAEJ,mCACI,WAEJ,mCACI,WAEJ,oCACI,WC5GZ,gDACI,iCACA,sBAEJ,uBACI,iBAEJ,wBACI,MlBSM,KkBRN,8BACI,MlBOE,KmBjBV,kCACI,iBnBaW,KmBTf,+BACI,eACA,cACA,wCACI,kBACA,aACA,sBAIJ,4CACI,kBACA,WAIJ,yCACI,kBCtBR,4BACI,iBpBaW,KoBTf,yBACI,eACA,cACA,kCACI,kBACA,aACA,sBAIJ,sCACI,kBACA,WAIJ,mCACI,kBCvBZ,YACI,iBrBemB,KqBdnB,aACA,iBACA,mBACI,MrBaM,KqBXV,yBACI,MrBUM,KqBRV,oBACI,iBrBMW,KqBLX,YAEJ,iBACI,6BAIA,wBACI,iBACA,iCAEJ,6BACI,iBrBRW,KqBUX,yCACI,iBrBXO,KqBaP,MrBXF,KqBaF,wCACI,iBrBhBO,KqBkBP,MrBhBF,KsBjBd,4BACI,GACI,aAEJ,KAEI,WAIR,4BACI,GACI,aAEJ,KAEI,WAKJ,6BACI,2CACA,sBAEJ,6BACI,2CACA,sBAKA,0EACI,YACA,aClCR,iBACI,iCACA,sBAEJ,iBACI,uCAEJ,iCACI,sBACA,mCACA,2BAEJ,sBACI,2BACA,sBAEJ,iBACI,iCACA,sBAEA,mBACI,sBAKR,YACA,sBAIA,uFACA,sBAIA,aACA,sBAIA,aACA,sBAGA,cACA,sBAIA,YACA,sBAGA,cACI,sBCvDR,aACE,0DACE,wBAEF,mBACE,wBAEF,yBACE,uBAEF,eACE,uBACA,mBACA,+CACE,aAEF,yBACE,yBAEF,wBACE,WACA,uBACA,uDACE,WAEF,+BACC,wBAED,2BACE,0BAGF,sCACE,wBAEF,uCACE,2BACA,iCACA,sBACA,iCACA,iBAEF,mCACE,YACA,gCC7CR,eACI,gBACA,MzBgBU,KyBfV,iBzBgBgB,gByBfhB,sBACA,gBCPJ,gBACI,YCDJ,yBACI,WACI,oBACA,iBACI,oBAEJ,iBACI,oBAEJ,kBACI,oBAEJ,0BACI,oBAEJ,yBACI,oBAEJ,oBACI,oBAEJ,qBACI,qBCpBJ,+CADJ,sBAEQ,UACA,aAEJ,yBACI,uDACI,2BAKR,+CADJ,wBAEQ,UACA,aASJ,yBADJ,gBAEQ,4BCdA,0BADJ,uBAEQ","sourcesContent":["/* Jektify\n========================================================*/\n@use \"sass:color\";\n\n/* Import fonts by Google Fonts - https://fonts.google.com/ */\n@import url('https://fonts.googleapis.com/css?family=Lato:300,400,700');\n\n\n/*  Jektify Style\n----------------------------------------------------------\n\n.jektify */\n\n.jektify{\n\n  /* Jektify Variables */\n  $jektify__background-color--dark: #282828;\n  $jektify__background-color--white: #FFF;\n  $jektify__font-family--primary: 'Lato', sans-serif;\n\n  *{\n    box-sizing: border-box;\n    -webkit-box-sizing: border-box;\n    -moz-box-sizing: border-box;\n  }\n\n  font-family: $jektify__font-family--primary;\n  border-radius: 0px;\n  overflow: hidden;\n  max-width: 980px;\n  margin: 30px auto;\n  -webkit-box-shadow: 0 8px 6px -6px black;\n  -moz-box-shadow: 0 8px 6px -6px black;\n  box-shadow: 0 10px 56px -6px black;\n  -webkit-transition: all 0.5s ease;\n  -moz-transition: all 0.5s ease;\n  -o-transition: all 0.5s ease;\n  transition: all 0.5s ease;\n\n  &:hover{\n    -webkit-box-shadow: none;\n    -moz-box-shadow: none;\n    box-shadow: none;\n  }\n\n  /* .jektify--dark */\n  &--dark{\n    background-color: $jektify__background-color--dark;\n    border: 1px solid #131313;\n    text-decoration: none !important;\n    &:hover{\n      opacity: 0.99;\n      text-decoration: none !important;\n    }\n  }\n\n  /* .jektify--white */\n  &--white{\n    background-color: $jektify__background-color--white;\n    border: 1px solid #adadad;\n    text-decoration: none !important;\n  }\n\n\n  /* .jektify__header */\n  &__header{\n      padding: 20px;\n      position: relative;\n      font-family: 'Lato', sans-serif;\n      border-bottom: solid 1px transparent;\n\n      -webkit-touch-callout: none;\n      -webkit-user-select: none;\n      -khtml-user-select: none;\n      -moz-user-select: none;\n      -ms-user-select: none;\n      user-select: none;\n      line-height: 2.2rem !important;\n      text-align: left;\n\n      /* .jektify__header--dark */\n      &--dark{\n        background-color: $jektify__background-color--dark;\n        text-decoration: none !important;\n      }\n\n      /* .jektify__header--white */\n      &--white{\n        background-color: $jektify__background-color--white;\n        text-decoration: none !important;\n      }\n\n  }\n\n\n  /* .jektify__brand */\n  &__brand{\n    text-decoration: none !important;\n    margin-right: 17px;\n    padding-bottom: 4px;\n    cursor: pointer;\n    font-size: 0.81em;\n    font-weight: 300;\n    letter-spacing: 0.15em;\n    -webkit-transition: all .45s;\n    -o-transition: all .45s;\n    transition: all .45s;\n\n    &:hover{\n      text-decoration: none !important;\n      opacity: 0.87;\n    }\n\n    /* .jektify__brand--dark */\n    &--dark{\n      border-bottom: 1px solid #1ed760;\n      background-color: $jektify__background-color--dark;\n      color: #1ed760;\n      &:hover{\n        color: #fff;\n        border-bottom: 1px solid #fff;\n      }\n    }\n\n\n    /* .jektify__brand--white */\n    &--white{\n      background-color: $jektify__background-color--white;\n      font-weight: 600;\n      color: #282828;\n      border-bottom: 1px solid #282828;\n      &:hover{\n        color: #1ed760;\n        border-bottom: 1px solid #1ed760;\n      }\n    }\n\n  }\n\n  /* .jektify__year */\n  &__year{\n      font-style: normal;\n      font-size: 0.81em;\n      font-family: inherit;\n      font-weight: 300;\n\n    /* .jektify__year--dark */\n    &--dark{\n      background-color: $jektify__background-color--dark;\n      color: #fff;\n    }\n\n    /* .jektify__year--white */\n    &--white{\n      background-color: $jektify__background-color--white;\n      font-weight: 600;\n      color: #282828;\n    }\n\n  }\n\n  /* .jektify__button */\n  &__button{\n      font-size: 2.5em;\n      float: right;\n      -webkit-transition: all .45s;\n      -o-transition: all .45s;\n      transition: all .45s;\n      right: 20px;\n      cursor: pointer;\n      font-weight: 300;\n\n      &:hover{\n        opacity: 0.87;\n      }\n\n      /* .jektify__button--dark */\n      &--dark{\n        color: #1ed760;\n        &:hover{\n          color: #fff;\n        }\n      }\n\n    /* .jektify__button--white */\n    &--white{\n      color: #282828;\n      &:hover{\n        color: #1ed760;\n      }\n    }\n\n    /* .jektify__button--open */\n    &--open{\n      transform: rotate(315deg);\n    }\n\n    /* .jektify__button--closed */\n    &--closed{\n      transform: rotate(0deg);\n    }\n  }\n\n  /* .jektify__title */\n  &__title{\n    font-family: inherit;\n    letter-spacing: 0.17em;\n    text-align: center;\n    font-size: 1.9em;\n\n   /* .jektify__title--dark */\n    &--dark{\n      background-color: $jektify__background-color--dark;\n      color: #fff;\n    }\n\n    /* .jektify__title--white */\n    &--white{\n      background-color: $jektify__background-color--white;\n    }\n\n  }\n\n  /* .jektify__body */\n  &__body{\n    padding: 0px;\n    -webkit-margin-start: 0px;\n    -moz-margin-start: 0px;\n    border-top: solid 1px rgba(0, 0, 0, 0.3);\n  }\n\n  /* .jektify__user */\n   &__user{\n     display: -webkit-box;\n     display: -ms-flexbox;\n     display: flex;\n     -ms-flex-wrap: wrap;\n     flex-wrap: wrap;\n     margin-right: -15px;\n     margin-left: -15px;\n     -webkit-box-pack: end !important;\n     -ms-flex-pack: end !important;\n     justify-content: flex-end !important;\n     line-height: 2.2rem !important;\n     margin: 20px 0px 20px 0px;\n\n     /* .jektify__user--white */\n     &--white{\n       color: #282828;\n     }\n\n     /* .jektify__user-link */\n      &-link{\n        border-bottom: 1px solid transparent;\n        margin-left: 40px;\n        height: 20px;\n        background-image: url(https://raw.githubusercontent.com/jektify/jektify/master/assets/vendor/jektify/imgs/spotify_logo.png);\n        background-repeat: no-repeat;\n        background-size: 20px;\n        margin-right: 20px;\n\n        &:hover{\n          text-decoration: none;\n        }\n      }\n\n     /* .jektify__user-text */\n      &-text{\n        font-size: 0.8em;\n        letter-spacing: 0.1em;\n        border-bottom: 1px solid transparent;\n        -webkit-transition: all .45s;\n        -o-transition: all .45s;\n        transition: all .45s;\n        margin-left: 30px;\n        margin-top: -12px;\n        float: left;\n\n        &:hover{\n          opacity: 0.87;\n        }\n\n        /* .jektify__user-text--dark */\n        &--dark{\n            border-bottom: 1px solid #1ed760;\n            color: #1ed760;\n\n        }\n\n        /* .jektify__user-text--white  */\n        &--white{\n          border-bottom: 1px solid #282828;\n          color: #282828;\n          &:hover{\n            color: #1ed760;\n            border-bottom: 1px solid #1ed760;\n          }\n        }\n      }\n   }\n\n  /* .jektify__description */\n  &__description{\n    font-family: inherit;\n    letter-spacing: 0.14em;\n    line-height: 1.9em;\n    font-weight: 300;\n    padding: 0px 15px;\n    text-align: center;\n    font-size: 1.1em;\n\n    /* .jektify__content--dark */\n    &--dark{\n      background-color: $jektify__background-color--dark;\n      color: #fff;\n    }\n\n   /* .jektify__content--white */\n    &--white{\n      background-color: $jektify__background-color--white;\n      color: #282828;\n    }\n\n  }\n\n /* .jektify__tracklist */\n  &__tracklist{\n    height: auto;\n    border-radius: 10px;\n    padding: 8px;\n    margin: 15px;\n    border: 1px solid color.adjust(#1ed760, $lightness: 1%);\n\n    /* .jektify__tracklist--dark */\n    &--dark{\n      background-color: $jektify__background-color--dark;\n    }\n\n    /* .jektify__tracklist--white */\n    &--white{\n      background-color: $jektify__background-color--white;\n      border: 1px solid color.adjust(#282828, $lightness: 1%);\n    }\n\n  }\n\n  /* .jektify__track */\n  &__track{\n\n    /* .jektify__track--dark */\n    &--dark{\n      background-color: $jektify__background-color--dark;\n    }\n\n    /* .jektify__track--white */\n    &--white{\n      background-color: $jektify__background-color--white;\n    }\n\n  }\n\n\n} /* END - .jektify */\n","@use \"../utils\" as *;\n\n// Underline all links.\n.underline_links{\n    *{\n        a{ text-decoration: underline; }\n    }\n}\n\n// Sidebar components\n.sidebar_avatar_background {\n    background-color: $elements__background;\n}\n\n.sidebar_avatar_border {\n    border: 0.12rem solid $color__clickable;\n}\n\n.sidebar_avatar_circle {\n    border-radius: 50%;\n}\n\n// Inputs components\n\n.inputs_style {\n    font-size: 1.8rem;\n    background-color: $elements__background;\n    width: 100%;\n    box-shadow: none;\n    border: none;\n    border-bottom: 1px solid $color__text;\n    outline: none;\n    border-radius: 0px;\n    height: auto;\n    &:hover,&:focus,&:active,&:visited{\n      background-color: $elements__background;\n      box-shadow: none;\n      outline: none;\n    }\n    &:focus, &:active, &:visited{\n      border-bottom: 1px solid $color__clickable;\n    }\n}\n\n// TextArea style\n.textarea_style {\n    background-color: $elements__background;\n    font-size: 1.17rem;\n    width: 100%;\n    box-shadow: none;\n    border: none;\n    border-left: 1px solid $color__text;\n    outline: none;\n    border-radius: 0px;\n    height: auto;\n    &:hover,&:focus,&:active,&:visited{\n        background-color: $elements__background;\n        box-shadow: none;\n        outline: none;\n      }\n    &:focus, &:active, &:visited{\n        border-left: 1px solid $color__clickable;\n    }\n}\n\n.elements_box {\n    background-color: $elements__background;\n    border-radius: 20px;\n    border: 1px solid $elements__box_border_color;\n}\n\n.element_opacity {\n    opacity: 1;\n    transition: 0.5s;\n    &:hover{\n        opacity: 0.75;\n        color: $color__text;\n    }\n}\n\n.buttons_style {\n    padding: 8px;\n    background-color: $color__clickable;\n    border-radius: 5px;\n    width: auto;\n    text-decoration: none !important;\n    color: $buttons__color;\n    opacity: 1;\n    min-width: 100px;\n    transition: 0.71s;\n    &:hover{\n        background-color: $color__clickable;\n        color: $buttons__color;\n        opacity: 0.84;\n    }\n    &:hover,&:focus,&:visited,&:active{\n        text-decoration: none;\n    }\n}\n\n// Text and Font for all texts.\n.content_text_font_size {\n    line-height: 1.8rem;\n    font-size: 1.12rem;\n    // p{\n        // font-size: 1.12rem;\n    // }\n}\n\n// Scrollbar modern\n.scrollbar_modern {\n    $boder: 10px;\n    $size: 7px;\n    /* Custom scrollbar */\n    ::-webkit-scrollbar {\n      width: $size;\n      height: $size;\n      margin-right: 9px;\n      background: $background__full;\n    }\n\n    /* Track - Bg */\n    ::-webkit-scrollbar-track {\n      -webkit-box-shadow: inset 0 0 6px transparent;\n      -webkit-border-radius: $boder;\n      border-radius: $boder;\n    }\n\n    /* Handle */\n    ::-webkit-scrollbar-thumb {\n      -webkit-border-radius: $boder;\n      border-radius: $boder;\n      background: $color__clickable;\n      -webkit-box-shadow: inset 0 0 6px $color__clickable;\n    }\n    ::-webkit-scrollbar-thumb:window-inactive {\n    background: $color__clickable;\n    }\n  }\n\n  /* Animation */\n.animation {\n    animation-name: fade;\n    animation-duration: 500ms;\n    &__move{\n        animation-name: move;\n        animation-duration: 500ms;\n        animation-delay: 250ms;\n        animation-fill-mode: backwards;\n    }\n    &__down{\n        animation-name: down;\n        animation-duration: 500ms;\n    }\n    &__pulse{\n        animation: pulse 1s linear;\n    }\n    &__sidebar-title{\n        animation: move 500ms;\n        animation-delay: 250ms;\n        animation-fill-mode: backwards;\n    }\n    &__sidebar-menu{\n        animation: move 600ms;\n        animation-delay: 290ms;\n        animation-fill-mode: backwards;\n    }\n    &__content{\n        animation: move_invert 670ms;\n        animation-delay: 310ms;\n        animation-fill-mode: backwards;\n    }\n    &__terminal{\n        animation: fade 670ms;\n        animation-delay: 310ms;\n        animation-fill-mode: backwards;\n    }\n}\n","@use \"sass:map\";\n\n$typing_theme: () !default;\n\n// helper para obter valor do map com fallback\n@function typing-get($key, $fallback) {\n  $val: map.get($typing_theme, $key);\n  @return if($val == null, $fallback, $val);\n}\n\n// Set\n$font-family__primary: typing-get(font-family__primary, ('Special Elite', cursive));\n$font-family__secondary: typing-get(font-family__secondary, ('Special Elite', cursive));\n$font-family__third: typing-get(font-family__third, ('Open Sans', sans-serif));\n$font-family__terminal: typing-get(font-family__terminal, ('Inconsolata', monospace));\n\n// definir as variáveis locais a partir do map (com fallback)\n$background__full: typing-get(background__full, #000000);\n$elements__background: typing-get(elements__background, #000000);\n$color__clickable: typing-get(color__clickable, #000000);\n$color__text: typing-get(color__text, #000000);\n$texts__background: typing-get(texts__background, rgba(0, 0, 0, 0.42));\n$hr__color: typing-get(hr__color, #000000);\n$elements__box_border_color: typing-get(elements__box_border_color, transparent);\n$terminal__shadow_color: typing-get(terminal__shadow_color, #000000);\n$buttons__color: typing-get(buttons__color, #000000);\n\n// Keyframes\n$keyframe__pulse_color_primary: typing-get(keyframe__pulse_color_primary, rgba(0, 0, 0, 0.158));\n$keyframe__pulse_color_secondary: typing-get(keyframe__pulse_color_secondary, rgba(0, 0, 0, 0.158));\n\n// Highlighter\n$highlight__background: typing-get(highlight__background, #000000);\n$highlight__border_color: typing-get(highlight__border_color, #000000);\n$highlight__color: typing-get(highlight__color, #000000);\n\n// Footer\n$footer__bg: typing-get(footer__bg, #000000);\n\n// Blockquote\n$blockquote__background: typing-get(blockquote__background, #000000);\n\n// Table\n$table__thead_th_background: typing-get(table__thead_th_background, #000000);\n$table__thead_th_color: typing-get(table__thead_th_color, #000000);\n$table__thead_th_border: typing-get(table__thead_th_border, #000000);\n$table__tbody_td_background: typing-get(table__tbody_td_background, #000000);\n$table__tbody_td_color: typing-get(table__tbody_td_color, #000000);\n$table__tbody_td_border: typing-get(table__tbody_td_border, #000000);\n\n// Gist theme\n$gist__background: typing-get(gist__background, #000000);\n$gist__code_color: typing-get(gist__code_color, #000000);\n$gist__border: typing-get(gist__border, (#000000 #000000 #000000));\n$gist__ln_background: typing-get(gist__ln_background, #000000);\n$gist__ln_color: typing-get(gist__ln_color, #000000);\n$gist__meta_color: typing-get(gist__meta_color, #000000);\n$gist__meta_link_color: typing-get(gist__meta_link_color, #000000);\n$gist__comment_color: typing-get(gist__comment_color, #000000);\n$gist__function_color: typing-get(gist__function_color, #000000);\n$gist__fn_color: typing-get(gist__fn_color, #000000);\n$gist__string_color: typing-get(gist__string_color, #000000);\n$gist__var_color: typing-get(gist__var_color, #000000);\n","/* Stylesheets for global elements\n––––––––––––––––––––––––––––––––––––––––––––––––––  */\n@use \"../utils\" as *;\n@use \"components\";\n\nhtml,body{\n  color: $color__text;\n  hr{\n    border-top: 1px solid $hr__color;\n  }\n  font: 100% verdana, arial, tahoma, sans-serif;\n  *{\n    a{\n      color: $color__clickable;\n      font-weight: bold;\n      &:hover{\n        color: $color__clickable;\n        text-decoration: none;\n      }\n      @extend .element_opacity;\n    }\n    a:focus {outline:0 !important;}\n    button:focus {outline:0 !important;}\n    input:focus {outline:0 !important;}\n  }\n  @extend .scrollbar_modern;\n}\n\nbody{\n  font-family: $font-family__primary;\n  background-color: $background__full;\n  overflow-x: hidden;\n  scroll-behavior: smooth;\n}\n","@use \"../utils\" as *;\n\n@keyframes fade {\n    from{\n        opacity: 0;\n        transform: scale(0.9);\n    }to{\n        opacity: 1;\n        transform: scale(1);\n    }\n}\n\n@keyframes move {\n    from{\n        opacity: 0;\n        transform: translateX(-35%)\n    }to{\n        opacity: 1;\n        transform: translateX(0%)\n    }\n}\n\n@keyframes move_invert {\n    from{\n        opacity: 0;\n        transform: translateX(35%)\n    }to{\n        opacity: 1;\n        transform: translateX(0%)\n    }\n}\n\n@keyframes down {\n    from{\n        opacity: 0;\n        transform: rotateY(-45%);\n    }to{\n        opacity: 1;\n        transform: rotateY(0%);\n    }\n}\n\n@keyframes pulse{\n  0% {\n    box-shadow: 0 0 0 0px $keyframe__pulse_color_primary;\n  }\n  100% {\n    box-shadow: 0 0 0 35px $keyframe__pulse_color_secondary;\n  }\n}\n","/* Stylesheets for include Highlight\n--------------------------------------------------------*/\n@use \"../utils\" as *;\n\n.highlight{\n  margin: 3% 0%;\n  font-size: 1.2rem;\n}\n\npre{\n  background-color: $highlight__background;\n  border-radius: 0px;\n  // padding: 2%;\n  border: 1px solid $highlight__border_color;\n  border-radius: 10px;\n  table{\n    margin: 0 !important;\n    tbody{\n      tr{\n        td{\n          background-color: $highlight__background;\n          border: 1px solid $highlight__border_color;\n        }\n      }\n    }\n  }\n  code{\n    color: $highlight__color;\n    border: none !important;\n    white-space: pre;\n    word-wrap: normal;\n    overflow-x: auto;\n    overflow-x: hidden;\n    .lineno{\n      -webkit-user-select: none;\n      -moz-user-select: none;\n      -o-user-select: none;\n      margin-right: 2%;\n      border-right: 0.1rem solid $highlight__border_color;\n    }\n    .lineno::-moz-selection {\n      background-color: transparent;\n    }\n    .lineno::selection {\n      background-color: transparent;\n    }\n    .hll { background-color: #ffffcc }\n    .c { color: #408080; font-style: italic } /* Comment */\n    .err { border: 1px solid #FF0000 } /* Error */\n    .k { color: #008000; font-weight: bold } /* Keyword */\n    .o { color: #666666 } /* Operator */\n    .ch { color: #408080; font-style: italic } /* Comment.Hashbang */\n    .cm { color: #408080; font-style: italic } /* Comment.Multiline */\n    .cp { color: #BC7A00 } /* Comment.Preproc */\n    .cpf { color: #408080; font-style: italic } /* Comment.PreprocFile */\n    .c1 { color: #408080; font-style: italic } /* Comment.Single */\n    .cs { color: #408080; font-style: italic } /* Comment.Special */\n    .gd { color: #A00000 } /* Generic.Deleted */\n    .ge { font-style: italic } /* Generic.Emph */\n    .gr { color: #FF0000 } /* Generic.Error */\n    .gh { color: #000080; font-weight: bold } /* Generic.Heading */\n    .gi { color: #00A000 } /* Generic.Inserted */\n    .go { color: #888888 } /* Generic.Output */\n    .gp { color: #000080; font-weight: bold } /* Generic.Prompt */\n    .gs { font-weight: bold } /* Generic.Strong */\n    .gu { color: #800080; font-weight: bold } /* Generic.Subheading */\n    .gt { color: #0044DD } /* Generic.Traceback */\n    .kc { color: #008000; font-weight: bold } /* Keyword.Constant */\n    .kd { color: #008000; font-weight: bold } /* Keyword.Declaration */\n    .kn { color: #008000; font-weight: bold } /* Keyword.Namespace */\n    .kp { color: #008000 } /* Keyword.Pseudo */\n    .kr { color: #008000; font-weight: bold } /* Keyword.Reserved */\n    .kt { color: #B00040 } /* Keyword.Type */\n    .m { color: #666666 } /* Literal.Number */\n    .s { color: #BA2121 } /* Literal.String */\n    .na { color: #7D9029 } /* Name.Attribute */\n    .nb { color: #008000 } /* Name.Builtin */\n    .nc { color: #0000FF; font-weight: bold } /* Name.Class */\n    .no { color: #880000 } /* Name.Constant */\n    .nd { color: #AA22FF } /* Name.Decorator */\n    .ni { color: #999999; font-weight: bold } /* Name.Entity */\n    .ne { color: #D2413A; font-weight: bold } /* Name.Exception */\n    .nf { color: #0000FF } /* Name.Function */\n    .nl { color: #A0A000 } /* Name.Label */\n    .nn { color: #0000FF; font-weight: bold } /* Name.Namespace */\n    .nt { color: #008000; font-weight: bold } /* Name.Tag */\n    .nv { color: #19177C } /* Name.Variable */\n    .ow { color: #AA22FF; font-weight: bold } /* Operator.Word */\n    .w { color: #bbbbbb } /* Text.Whitespace */\n    .mb { color: #666666 } /* Literal.Number.Bin */\n    .mf { color: #666666 } /* Literal.Number.Float */\n    .mh { color: #666666 } /* Literal.Number.Hex */\n    .mi { color: #666666 } /* Literal.Number.Integer */\n    .mo { color: #666666 } /* Literal.Number.Oct */\n    .sa { color: #BA2121 } /* Literal.String.Affix */\n    .sb { color: #BA2121 } /* Literal.String.Backtick */\n    .sc { color: #BA2121 } /* Literal.String.Char */\n    .dl { color: #BA2121 } /* Literal.String.Delimiter */\n    .sd { color: #BA2121; font-style: italic } /* Literal.String.Doc */\n    .s2 { color: #BA2121 } /* Literal.String.Double */\n    .se { color: #BB6622; font-weight: bold } /* Literal.String.Escape */\n    .sh { color: #BA2121 } /* Literal.String.Heredoc */\n    .si { color: #BB6688; font-weight: bold } /* Literal.String.Interpol */\n    .sx { color: #008000 } /* Literal.String.Other */\n    .sr { color: #BB6688 } /* Literal.String.Regex */\n    .s1 { color: #BA2121 } /* Literal.String.Single */\n    .ss { color: #19177C } /* Literal.String.Symbol */\n    .bp { color: #008000 } /* Name.Builtin.Pseudo */\n    .fm { color: #0000FF } /* Name.Function.Magic */\n    .vc { color: #19177C } /* Name.Variable.Class */\n    .vg { color: #19177C } /* Name.Variable.Global */\n    .vi { color: #19177C } /* Name.Variable.Instance */\n    .vm { color: #19177C } /* Name.Variable.Magic */\n    .il { color: #666666 } /* Literal.Number.Integer.Long */\n  }\n}\n","/*\n––––––––––––––––––––––––––––––––––––––––––––––––––  */\n@use \"../utils\" as *;\n\ntable{\n    margin: 2% 0%;\n    width: 100%;\n    thead{\n      tr{\n        th{\n          padding: 5px;\n          border: 1px solid $table__thead_th_border;\n          color: $table__thead_th_color;\n          background-color: $table__thead_th_background;\n        }\n      }\n    }\n    tbody{\n      background-color: $table__tbody_td_background;\n      tr{\n        td{\n          padding: 5px;\n          border: 1px solid $table__tbody_td_border;\n          color: $table__tbody_td_color;\n          background-color: $table__tbody_td_background;\n          code{\n            background-color: transparent;\n          }\n        }\n      }\n    }\n  }","/*\n––––––––––––––––––––––––––––––––––––––––––––––––––  */\n@use \"../utils\" as *;\n\nblockquote{\n    border: none !important;\n    background-color: $blockquote__background;\n    border-left: 5px solid $color__clickable !important;\n    padding: 10px 10px 0px 10px;\n    border-top-left-radius: 0px;\n    border-bottom-left-radius: 0px;\n    border-bottom-right-radius: 0px;\n    p{\n      padding-bottom: 10px;\n    }\n  }","#markdown-toc {\n    margin-bottom: 100px;\n    &:before{\n      content: attr(data-content);\n      font-weight: bold;\n      font-size: 1.8rem;\n    }\n  }","@use \"../base/components\";\n\n.layout_hello {\n    @extend .elements_box;\n    @extend .content_text_font_size;\n    // line-height: 1.8rem;\n    // p{font-size: 1.12rem;}\n\n    // 1920x1080\n    @media (min-width: 1920px) {\n        margin-top: 194px;\n    }\n}","@use \"../utils\" as *;\n@use \"../base/components\";\n\n.layout_postlist {\n\n    &__header, &__content{\n        @extend .elements_box;\n        @extend .content_text_font_size;\n    }\n    &__comments{\n        background-color: $texts__background;\n        font-size: 0.97rem;\n        color: $color__text;\n        // &-count{}\n    }\n    &__time{\n        background-color: $texts__background;\n        opacity: 0.77;\n        color: $color__text;\n        border-radius: 5px;\n    }\n    &__excerpted{\n        background-color: $texts__background;\n        border-radius: 5px;\n        line-height: 1.8rem;\n    }\n    &__comments{\n        .fa-comments{\n            margin: 0px 4px;\n        }\n        .disqus-comment-count{\n            color: $color__clickable;\n        }\n    }\n    &__pagination{\n        &-newer{\n            @extend .buttons_style;\n            border-radius: 0px;\n            border: 1px solid $color__clickable;\n            &:hover{\n                border: 1px solid $color__clickable;\n            }\n        }\n        &-counter{\n            color: $color__clickable;\n            background-color: $elements__background;\n            border: 1px solid;\n            &:hover{\n                color: $color__clickable;\n                background-color: $elements__background;\n                border: 1px solid;\n            }\n        }\n        &-older{\n            @extend .buttons_style;\n            border-radius: 0px;\n            border: 1px solid $color__clickable;\n            &:hover{\n                border: 1px solid $color__clickable;\n            }\n        }\n    }\n}","@use \"../utils\" as *;\n@use \"../base/components\";\n\n.layout_post {\n    @extend .content_text_font_size;\n    &__header, &__content, &__footer, &__disqus{\n        @extend .elements_box;\n    }\n    &__comments{\n        background-color: $texts__background;\n        color: $color__text;\n        font-size: 1rem;\n        // &-count{}\n    }\n    &__share-link {\n\n        &--text{\n            visibility: hidden;\n            font-size: 14px;\n            position: absolute;\n            top: 65px;\n            left: 50%;\n            -moz-transform: translate(-50%, 0%);\n            -o-transform: translate(-50%, 0%);\n            -ms-transform: translate(-50%, 0%);\n            -webkit-transform: translate(-50%, 0%);\n            transform: translate(-50%, 0%);\n        }\n\n        &:hover{\n            .layout_post__share-link--text {\n              visibility: visible;\n            }\n        }\n\n    }\n    &__share-icon{\n        font-size: 50px;\n        margin: 15px 0px;\n    }\n    &__author{\n        &-img{\n            border-radius: 50%;\n            border: 1px solid $color__text;\n            padding: 3px;\n        }\n    }\n\n}","@use \"../base/components\";\n\n.layout_contact {\n    @extend .content_text_font_size;\n\n    &__header, &__form, &__note{\n        @extend .elements_box;\n    }\n    &__input{\n        @extend .inputs_style;\n        font-size: 1.3rem;\n    }\n    &__textarea{\n        @extend .textarea_style;\n    }\n    &__form-button{\n        @extend .buttons_style;\n    }\n}","/* Stylesheets for layout Search\n––––––––––––––––––––––––––––––––––––––––––––––––––  */\n@use \"../utils\" as *;\n@use \"../base/components\";\n\n.layout-search {\n    @extend .elements_box;\n    @extend .content_text_font_size;\n  &__form{\n    border-radius: 0px;\n    height: auto;\n    &-group{\n      &:hover,&:focus,&:active,&:visited{\n        box-shadow: none !important;\n        border: none;\n        outline: none;\n      }\n    }\n  }\n  &__description{\n    font-size: 1.2rem;\n  }\n  &__shellicon{\n    font-size: 1.8rem;\n    margin-top: 1rem;\n  }\n  &__input {\n    @extend .inputs_style;\n    @media (min-width: 300px) and (max-width: 992px) {\n      font-size: 1.2rem !important;\n    }\n  }\n  &__btn-clear {\n    @extend .buttons_style;\n    &:hover,&:focus,&:active,&:visited{\n      text-decoration: none;\n    }\n  }\n  &__data{\n    list-style: none;\n    margin: 15px 0px;\n    font-size: 1.3rem;\n    li{\n      margin: 15px 0px;\n    }\n    transition: 0.9s;\n    a{\n      transition: 0.9s;\n      &:hover{\n        transition: 0.9s;\n        .layout-search__data__entry-date{\n          transition: 0.9s;\n          background-color: $color__text;\n        }\n      }\n    }\n    &__entry-date{\n      font-size: 0.9rem;\n      padding: 5px;\n      background-color: $color__clickable;\n      margin-left: 10px;\n      border-radius: 0px;\n      color: #fff;\n    }\n    &__not-search{\n      padding: 15px 0;\n      color: red;\n      font-size: 1.7rem;\n    }\n  }\n}\n","@use \"../utils\" as *;\n@use \"../base/components\";\n\n.layout_tag {\n    &__header, &__content {\n    \t@extend .content_text_font_size;\n        @extend .elements_box;\n    }\n    &__time {\n        background-color: $texts__background;\n        opacity: 0.77;\n        color: $color__text;\n        border-radius: 5px;\n    }\n    // &__comments {\n    //     &-count{}\n    // }\n}","@use \"../base/components\";\n\n.layout_error {\n    &__header, &__content{\n        @extend .elements_box;\n    }\n    &__icon{\n        font-size: 8rem;\n        color: red;\n    }\n    &__content{\n        @extend .content_text_font_size;\n    }\n}","@use \"../utils\" as *;\n@use \"../base/components\";\n\n.layout_resume {\n    @extend .content_text_font_size;\n\n    &__btnprint{\n      @extend .buttons_style;\n    }\n    &__header{\n      @extend .elements_box;\n    }\n    &__photo_cv{\n      margin-top: -15px;\n    }\n    &__content{\n      font-family: $font-family__third;\n      @extend .elements_box;\n    }\n  }","@use \"../utils\" as *;\n\n.sidebar{\n    background-color: $background__full;\n    &__avatar_flip {\n        // position: relative;\n        perspective: 1000;\n        margin: 10px auto;\n        width: 165px;\n        height: 165px;\n        &-card{\n            transform-style: preserve-3d;\n            transition: all 1.0s linear;\n        }\n        &-face{\n            position: absolute;\n            backface-visibility: hidden;\n            opacity: 1 !important;\n        }\n    }\n    .sidebar__avatar_flip-back.sidebar__avatar_flip-face{\n        display: block;\n        transform: rotateY(180deg);\n    }\n    &__avatar_flip, &__avatar_noflip{\n        .image_avatar{\n            width: 165px;\n            height: 165px;\n        }\n    }\n    &__title{\n        font-family: $font-family__secondary;\n        background-color: $elements__background;\n        border-radius: 20px;\n        color: $color__clickable;\n        border: 1px solid $elements__box_border_color;\n    }\n    &__menu{\n        font-family: $font-family__secondary;\n        background-color: $elements__background;\n        border-radius: 20px;\n        border: 1px solid $elements__box_border_color;\n        &-title{\n          font-size: 1.3rem;\n        }\n        &-link{\n          font-size: 1.3rem;\n          line-height: 1.64rem;\n          &:hover{\n            text-decoration: underline;\n          }\n        }\n    }\n}\n","/* Stylesheets for include Footer\n––––––––––––––––––––––––––––––––––––––––––––––––––  */\n@use \"../utils\" as *;\n\n.footer{\n  background-color: $footer__bg;\n  font-size: 0.8rem;\n  color: $color__text;\n}\n\n.scrolltop{\n  color: $color__text;\n  font-size: 3rem;\n  &__button{\n    font-size: 3rem !important;\n  }\n}\n","/*\n––––––––––––––––––––––––––––––––––––––––––––––––––  */\n@use \"../utils\" as *;\n\n.intro{\n    &__terminal{\n        font-family: $font-family__terminal;\n        // @media (max-width: 768px) {\n        // display: none;\n        // }\n        margin-top: 2%;\n        -webkit-box-shadow: 0px 0px 56px -3px $terminal__shadow_color;\n        -moz-box-shadow: 0px 0px 56px -3px $terminal__shadow_color;\n        box-shadow: 0px 0px 56px -3px $terminal__shadow_color;\n        border-radius: 7px 7px 5px 5px;\n\n        /* .intro__terminal .header */\n        .header{\n        background: #000;\n        border-radius: 7px 7px 0 0;\n        padding-left: 10px;\n        color: #fff;\n\n        /* .header__btn */\n        &__btn{\n            float: left;\n            padding: 0;\n            width: 12px;\n            height: 12px;\n            margin: 8px 5px 0 0;\n            display: inline-block;\n            border-radius: 50%;\n\n            /* .header__btn--green */\n            &--green{\n            background-color: #3BB662;\n            } /* END - .header__btn--green */\n\n            /* .header__btn--yellow */\n            &--yellow{\n            background-color: #ffe609;\n            } /* END - .header__btn--yellow */\n\n            /* .header__btn--red */\n            &--red{\n            background-color: #ec4d3b;\n            } /* END - .header__btn--red */\n\n        } /* END - .header__btn */\n\n        } /* END - .intro__terminal .header */\n\n\n        /* .intro__terminal .title */\n        .title{\n        font-size: 9pt !important;\n        text-align: center;\n        padding: 3px 0px;\n\n        /* .intro__terminal .title__text */\n        &__text{\n            margin-left: -56px;\n            color: #fff;\n        } /* END -.intro__terminal .title__text */\n\n        } /* END - .intro__terminal .titl */\n\n\n        /* .intro__terminal .body */\n        .body{\n        color: #3bff1a;\n        background: #000;\n        padding: 10px;\n        box-sizing: border-box;\n        width: 100%;\n        overflow: auto;\n        font-weight: 400;\n        min-height: 250px;\n        border-radius: 0 0 5px 5px;\n        line-height: 1.3rem;\n        font-size: 12pt !important;\n        p{\n            a{\n                color: #3BB662;\n            }\n        }\n\n        /* .intro__terminal .body__output */\n        &__output{\n            min-height: 21px !important;\n            span{\n                display: inline;\n                min-height: 21px !important;\n            }\n            &:after {\n            content:\" _\";\n            opacity: 0;\n            color: white;\n            animation: cursor 1s infinite;\n            min-height: 21px !important;\n            }\n            &__user{\n                color: magenta;\n            }\n            &__at{\n                color: white;\n            }\n            &__os{\n                color: yellow;\n            }\n            &__dir{\n                color: cyan;\n            }\n        } /* END - .intro__terminal .body__output */\n\n        } /* END - .intro__terminal .body */\n    } /* END - .intro__terminal */\n}","@use \"../utils\" as *;\n\n.socials_network{\n    &__header, &__body{\n        background-color: $background__full !important;\n        border: 1px solid $color__text;\n    }\n    &__icon{\n        font-size: 3.5rem;\n    }\n    &__close{\n        color: $color__text;\n        &:hover{\n            color: $color__text;\n        }\n    }\n}","@use \"../utils\" as *;\n\n.email_successfully_sent{\n    &__content{\n        background-color: $background__full;\n    }\n    &__header{}\n    &__body{}\n    &__icon{\n        font-size: 7rem;\n        color: #24aa20;\n        .el_icon{\n            border-radius: 50%;\n            padding: 20px;\n            background-color: #fff;\n        }\n    }\n    &__message_header{\n        h4{\n            font-size: 1.67rem;\n            color: $color__text;\n        }\n    }\n    &__message_body{\n        p{\n            font-size: 1.43rem;\n        }\n    }\n}","@use \"../utils\" as *;\n\n.email_failed_sent{\n    &__content{\n        background-color: $background__full;\n    }\n    &__header{}\n    &__body{}\n    &__icon{\n        font-size: 7rem;\n        color: #e61923;\n        .el_icon{\n            border-radius: 50%;\n            padding: 20px;\n            background-color: #fff;\n        }\n    }\n    &__message_header{\n        h4{\n            font-size: 1.67rem;\n            color: $color__text;\n        }\n    }\n    &__message_body{\n        p{\n            font-size: 1.43rem;\n        }\n    }\n}","@use \"../utils\" as *;\n\n.affiliates{\n    background-color: $elements__background;\n    padding: 20px;\n    padding-top: 40px;\n    &__title{\n        color: $color__text;\n    }\n    &__description{\n        color: $color__text;\n    }\n    &__footer{\n        background-color: $color__clickable;\n        border: none;\n    }\n    &__btn{\n        border-radius: 0px !important;\n\n    }\n    &__wrap{\n        .card{\n            min-height: 280px;\n            border: 1px solid $color__clickable !important;\n        }\n        .card-body{\n            background-color: $elements__background;\n            // background-color: transparent !important;\n            .card-title{\n                background-color: $elements__background;\n                // background-color: transparent !important;\n                color: $color__text;\n            }\n            .card-text{\n                background-color: $elements__background;\n                // background-color: transparent !important;\n                color: $color__text;\n            }\n        }\n    }\n}","@use \"../utils\" as *;\n@use \"../base/components\";\n\n@keyframes avatar_vvfolded1{\n    0% {\n        fill: #ffe609;\n    }\n    100% {\n        // fill: #3BB662;\n        fill: #FFF;\n    }\n}\n\n@keyframes avatar_vvfolded2{\n    0% {\n        fill: #ffe609;\n    }\n    100% {\n        // fill: #3BB662;\n        fill: #FFF;\n    }\n}\n\n.animation{\n    &__avatar_vvfolded1{\n        animation: avatar_vvfolded1 2200ms infinite;\n        animation-delay: 500ms;\n    }\n    &__avatar_vvfolded2{\n        animation: avatar_vvfolded2 2200ms infinite;\n        animation-delay: 500ms;\n    }\n}\n.sidebar{\n    &__avatar_noflip, &__avatar_flip{\n        .svg_vvfolded{\n            width: 165px;\n            height: 165px;\n            // &__vvfolded1{\n            //     @extend .animation__avatar_vvfolded1;\n            // }\n            // &__vvfolded2{\n            //     @extend .animation__avatar_vvfolded2;\n            // }\n            // &__background{}\n        }\n    }\n}","@use \"../utils\" as *;\n\n.gist{\n    .gist-data{\n        background-color: $gist__background !important;\n        color: $gist__code_color !important;\n    }\n    .gist-file{\n        border-color: $gist__border !important;\n    }\n    .blob-code, .blob-num{\n        color: $gist__code_color !important;\n        border: 0.1rem solid $gist__background !important;\n        background: $gist__background !important;\n    }\n    .js-line-number{\n        background: $gist__ln_background !important;\n        color: $gist__ln_color !important;\n    }\n    .gist-meta{\n        background-color: $gist__background !important;\n        color: $gist__meta_color !important;\n        /* Link meta */\n        a{\n            color: $gist__meta_link_color !important;\n        }\n    }\n\n    /* Comments */\n    .pl-c{\n    color: $gist__comment_color !important;\n    }\n\n    /* Function */\n    .pl-k, tbody tr:first-child .blob-code, tbody tr:last-child .blob-code{\n    color: $gist__function_color !important;\n    }\n\n    /* Function Name */\n    .pl-en{\n    color: $gist__fn_color !important;\n    }\n\n    /* Function Method */\n    .pl-c1{\n    color: $gist__fn_color !important;\n    }\n    /* \"'s around Strings */\n    .pl-pds{\n    color: $gist__string_color !important;\n    }\n\n    /* Strings */\n    .pl-s{\n    color: $gist__string_color !important;\n    }\n\n    .pl-smi{\n        color: $gist__var_color !important;\n    }\n  }","/* Stylesheets for print page Resume\n---------------------------------------------------------------*/\n\n@media print {\n  .sidebar,.footer, .scrolltop, #markdown-toc, .remove-printer{\n    display: none !important;\n  }\n  .scrolltop__button{\n    display: none !important;\n  }\n  .layout_default__content{\n    border: none !important;\n  }\n  .layout_resume{\n    border: none !important;\n    line-height: 1.5rem;\n    &__header, &__excerpt{\n      display: none;\n    }\n    &__photo_cv{\n      display: block !important;\n    }\n    &__content{\n      color: #000;\n      border: none !important;\n      a,code{\n        color: #000;\n      }\n      .emoji{\n      \tdisplay: none !important;\n      }\n      hr{\n        border-top: 1px solid #000;\n      }\n      /* Avoid printing hrefs when this class is applied */\n      a[href]:after {\n        content: none !important;\n      }\n      .badge__plugin{\n        box-shadow: none !important;\n        border: 1px solid #000 !important;\n        color: #000 !important;\n        background-color: white !important;\n        font-weight: bold;\n      }\n      blockquote{\n        border: none;\n        background-color: transparent;\n      }\n    }\n  }\n}\n","@use \"../utils\" as *;\n\n.badge__plugin {\n    font-weight: 200;\n    color: $color__text;\n    background-color: $texts__background;\n    border: 1px solid $color__text;\n    box-shadow: none;\n}\n",".imager__plugin{\n    margin: 15px;\n    // max-width: 220px;\n}","@media (max-width: 770px) { \n    .animation {\n        animation-name: none;\n        &__move{\n            animation-name: none;\n        }\n        &__down{\n            animation-name: none;\n        }\n        &__pulse{\n            animation-name: none;\n        }\n        &__sidebar-title{\n            animation-name: none;\n        } \n        &__sidebar-menu{\n            animation-name: none;\n        }\n        &__content{\n            animation-name: none;\n        }\n        &__terminal{\n            animation-name: none;\n        }\n    }\n}",".sidebar{\n    &__avatar_flip{\n        @media (min-width: 575px) and (max-width: 992px){\n            width: 20%;\n            height: auto;\n        }\n        @media (min-width: 768px){\n            &:hover .sidebar__avatar_flip-card {\n                transform: rotateY(180deg);\n            }\n        }\n    }\n    &__avatar_noflip{\n        @media (min-width: 575px) and (max-width: 992px){\n            width: 20%;\n            height: auto;\n        }\n        // img{\n        //     @media (max-width: 992px){\n        //         width: 90px;\n        //     }\n        // }\n    }\n    &__title{\n        @media (max-width: 992px){\n            text-align: left !important;\n        }\n    }\n    // &__menu{\n        // @media (min-width: 768px) and (max-width: 992px) {\n        //   width: 190px;\n        //   margin: 0 auto;\n        // }\n    // }\n}\n","/* \n––––––––––––––––––––––––––––––––––––––––––––––––––  */\n\n.intro{\n    &__terminal{\n        // @media (max-width: 768px) {\n        // display: none;\n        // }\n\n        /* .intro__terminal .body */\n        .body{\n            @media (max-width: 1200px) {\n                background: rgba(30, 30, 31, 1);\n            }\n        } /* END - .intro__terminal .body */\n    } /* END - .intro__terminal */\n}"],"file":"hacking.css"}
