	"sourcesContent": [
		"@import \"themes/hacking\";\n@import \"highlighter/highlighter\";\n@import \"base/base\";\n@import \"markdown/markdown\";\n@import \"layouts/layouts\";\n@import \"includes/includes\";\n@import \"gist/gist\";\n@import \"print/print\";\n@import \"plugins/plugins\";\n\n// Mobile\n@import \"mobile/mobile\";",
		"/* Theme Hacking\r\n––––––––––––––––––––––––––––––––––––––––––––––––––  */\r\n// Default\r\n$background__full: #000 !default;\r\n$elements__background: #0a0a0a !default;\r\n$color__clickable: #1ad62a !default;\r\n$color__text: #ffffff !default;\r\n$texts__background: #161616 !default;\r\n$hr__color: rgb(255, 255, 255) !default;\r\n$elements__box_border_color: transparent;\r\n$terminal__shadow_color: #636363;\r\n$buttons__color: #000 !default;\r\n\r\n// Keyframes\r\n$keyframe__pulse_color_primary: rgba(228, 228, 228, 0.158);\r\n$keyframe__pulse_color_secondary: rgba(233, 233, 233, 0.103);\r\n\r\n// Highlighter\r\n$highlight__background: #000;\r\n$highlight__border_color: #000;\r\n$highlight__color: #fff;\r\n\r\n// Footer\r\n$footer__bg: rgb(0, 0, 0) !default;\r\n\r\n// Blockquote\r\n$blockquote__background: #131313;\r\n\r\n// Table\r\n$table__thead_th_background: #1b1b1b;\r\n$table__thead_th_color: #fff;\r\n$table__thead_th_border: #0e0e0e;\r\n$table__tbody_td_background: #1b1b1b;\r\n$table__tbody_td_color: #fff;\r\n$table__tbody_td_border: #0e0e0e;\r\n\r\n// Gist theme\r\n$gist__background: #0f0f0f;\r\n$gist__code_color: white;\r\n$gist__border: #1a1a1a #1a1a1a #1a1a1a;\r\n$gist__ln_background: #1a1a1a;\r\n$gist__ln_color: black;\r\n$gist__meta_color: white;\r\n$gist__meta_link_color: #1ad62a;\r\n$gist__comment_color: #386931;\r\n$gist__function_color: #246194;\r\n$gist__fn_color: #ad8500;\r\n$gist__string_color: #c55829;\r\n$gist__var_color: #132b44;",
		"/* Stylesheets for include Highlight\r\n--------------------------------------------------------*/\r\n\r\n.highlight{\r\n  margin: 3% 0%;\r\n  font-size: 1.2rem;\r\n}\r\n\r\npre{\r\n  background-color: $highlight__background;\r\n  border-radius: 0px;\r\n  // padding: 2%;\r\n  border: 1px solid $highlight__border_color;\r\n  border-radius: 10px;\r\n  table{\r\n    margin: 0 !important;\r\n    tbody{\r\n      tr{\r\n        td{\r\n          background-color: $highlight__background;\r\n          border: 1px solid $highlight__border_color;\r\n        }\r\n      }\r\n    }\r\n  }\r\n  code{\r\n    color: $highlight__color;\r\n    border: none !important;\r\n    white-space: pre;\r\n    word-wrap: normal;\r\n    overflow-x: auto;\r\n    overflow-x: hidden;\r\n    .lineno{\r\n      -webkit-user-select: none;\r\n      -moz-user-select: none;\r\n      -o-user-select: none;\r\n      margin-right: 2%;\r\n      border-right: 0.1rem solid $highlight__border_color;\r\n    }\r\n    .lineno::-moz-selection {\r\n      background-color: transparent;\r\n    }\r\n    .lineno::selection {\r\n      background-color: transparent;\r\n    }\r\n    @import \"pygments\";\r\n  }\r\n}\r\n",
		"/* Generate by command: $ pygmentize -S default -f html > ~/highlight.css\r\n   Themes: http://jwarby.github.io/jekyll-pygments-themes/languages/ruby.html\r\n-------------------------------------------------------------------------*/\r\n\r\n.hll { background-color: #ffffcc }\r\n.c { color: #408080; font-style: italic } /* Comment */\r\n.err { border: 1px solid #FF0000 } /* Error */\r\n.k { color: #008000; font-weight: bold } /* Keyword */\r\n.o { color: #666666 } /* Operator */\r\n.ch { color: #408080; font-style: italic } /* Comment.Hashbang */\r\n.cm { color: #408080; font-style: italic } /* Comment.Multiline */\r\n.cp { color: #BC7A00 } /* Comment.Preproc */\r\n.cpf { color: #408080; font-style: italic } /* Comment.PreprocFile */\r\n.c1 { color: #408080; font-style: italic } /* Comment.Single */\r\n.cs { color: #408080; font-style: italic } /* Comment.Special */\r\n.gd { color: #A00000 } /* Generic.Deleted */\r\n.ge { font-style: italic } /* Generic.Emph */\r\n.gr { color: #FF0000 } /* Generic.Error */\r\n.gh { color: #000080; font-weight: bold } /* Generic.Heading */\r\n.gi { color: #00A000 } /* Generic.Inserted */\r\n.go { color: #888888 } /* Generic.Output */\r\n.gp { color: #000080; font-weight: bold } /* Generic.Prompt */\r\n.gs { font-weight: bold } /* Generic.Strong */\r\n.gu { color: #800080; font-weight: bold } /* Generic.Subheading */\r\n.gt { color: #0044DD } /* Generic.Traceback */\r\n.kc { color: #008000; font-weight: bold } /* Keyword.Constant */\r\n.kd { color: #008000; font-weight: bold } /* Keyword.Declaration */\r\n.kn { color: #008000; font-weight: bold } /* Keyword.Namespace */\r\n.kp { color: #008000 } /* Keyword.Pseudo */\r\n.kr { color: #008000; font-weight: bold } /* Keyword.Reserved */\r\n.kt { color: #B00040 } /* Keyword.Type */\r\n.m { color: #666666 } /* Literal.Number */\r\n.s { color: #BA2121 } /* Literal.String */\r\n.na { color: #7D9029 } /* Name.Attribute */\r\n.nb { color: #008000 } /* Name.Builtin */\r\n.nc { color: #0000FF; font-weight: bold } /* Name.Class */\r\n.no { color: #880000 } /* Name.Constant */\r\n.nd { color: #AA22FF } /* Name.Decorator */\r\n.ni { color: #999999; font-weight: bold } /* Name.Entity */\r\n.ne { color: #D2413A; font-weight: bold } /* Name.Exception */\r\n.nf { color: #0000FF } /* Name.Function */\r\n.nl { color: #A0A000 } /* Name.Label */\r\n.nn { color: #0000FF; font-weight: bold } /* Name.Namespace */\r\n.nt { color: #008000; font-weight: bold } /* Name.Tag */\r\n.nv { color: #19177C } /* Name.Variable */\r\n.ow { color: #AA22FF; font-weight: bold } /* Operator.Word */\r\n.w { color: #bbbbbb } /* Text.Whitespace */\r\n.mb { color: #666666 } /* Literal.Number.Bin */\r\n.mf { color: #666666 } /* Literal.Number.Float */\r\n.mh { color: #666666 } /* Literal.Number.Hex */\r\n.mi { color: #666666 } /* Literal.Number.Integer */\r\n.mo { color: #666666 } /* Literal.Number.Oct */\r\n.sa { color: #BA2121 } /* Literal.String.Affix */\r\n.sb { color: #BA2121 } /* Literal.String.Backtick */\r\n.sc { color: #BA2121 } /* Literal.String.Char */\r\n.dl { color: #BA2121 } /* Literal.String.Delimiter */\r\n.sd { color: #BA2121; font-style: italic } /* Literal.String.Doc */\r\n.s2 { color: #BA2121 } /* Literal.String.Double */\r\n.se { color: #BB6622; font-weight: bold } /* Literal.String.Escape */\r\n.sh { color: #BA2121 } /* Literal.String.Heredoc */\r\n.si { color: #BB6688; font-weight: bold } /* Literal.String.Interpol */\r\n.sx { color: #008000 } /* Literal.String.Other */\r\n.sr { color: #BB6688 } /* Literal.String.Regex */\r\n.s1 { color: #BA2121 } /* Literal.String.Single */\r\n.ss { color: #19177C } /* Literal.String.Symbol */\r\n.bp { color: #008000 } /* Name.Builtin.Pseudo */\r\n.fm { color: #0000FF } /* Name.Function.Magic */\r\n.vc { color: #19177C } /* Name.Variable.Class */\r\n.vg { color: #19177C } /* Name.Variable.Global */\r\n.vi { color: #19177C } /* Name.Variable.Instance */\r\n.vm { color: #19177C } /* Name.Variable.Magic */\r\n.il { color: #666666 } /* Literal.Number.Integer.Long */\r\n",
		"/* \r\n––––––––––––––––––––––––––––––––––––––––––––––––––  */\r\n@import \"fonts\";\r\n@import \"global\";\r\n@import \"components\";\r\n@import \"keyframes\";\r\n",
		"/* Fonts\r\n––––––––––––––––––––––––––––––––––––––––––––––––––  */\r\n\r\n// Loading font active.\r\n$font-family__load1: 'Special Elite', cursive;\r\n$font-family__load2: 'Open Sans', sans-serif; \r\n$font-family__load3: 'Inconsolata', monospace;\r\n\r\n// Loading font inactive.\r\n$font-family__load4: 'Roboto', sans-serif;\r\n$font-family__load5: 'Gloria Hallelujah', cursive;\r\n$font-family__load6: -apple-system,BlinkMacSystemFont,segoe ui,Roboto,Oxygen,Ubuntu,Cantarell,open sans,helvetica neue,sans-serif;\r\n\r\n// Set\r\n$font-family__primary: $font-family__load1;\r\n$font-family__secondary: $font-family__load1;\r\n$font-family__third: $font-family__load2;\r\n$font-family__terminal: $font-family__load3;\r\n\r\n",
		"/* Stylesheets for global elements\r\n––––––––––––––––––––––––––––––––––––––––––––––––––  */\r\n\r\nhtml,body{\r\n  color: $color__text;\r\n  hr{\r\n    border-top: 1px solid $hr__color;\r\n  }\r\n  font: 100% verdana, arial, tahoma, sans-serif;\r\n  *{\r\n    a{\r\n      color: $color__clickable;\r\n      font-weight: bold;\r\n      &:hover{\r\n        color: $color__clickable;\r\n        text-decoration: none;\r\n      }\r\n      @extend .element_opacity;\r\n    }\r\n    a:focus {outline:0 !important;}\r\n    button:focus {outline:0 !important;}\r\n    input:focus {outline:0 !important;}\r\n  }\r\n  @extend .scrollbar_modern;\r\n}\r\n\r\nbody{\r\n  font-family: $font-family__primary;\r\n  background-color: $background__full;\r\n  overflow-x: hidden;\r\n  scroll-behavior: smooth;\r\n}\r\n",
		"// Underline all links.\r\n.underline_links{\r\n    *{\r\n        a{ text-decoration: underline; }\r\n    }\r\n}\r\n\r\n// Sidebar components\r\n.sidebar_avatar_background{\r\n    background-color: $elements__background;\r\n}\r\n\r\n.sidebar_avatar_border{\r\n    border: 0.12rem solid $color__clickable;\r\n}\r\n\r\n.sidebar_avatar_circle{\r\n    border-radius: 50%;\r\n}\r\n\r\n// Inputs components\r\n\r\n.inputs_style{\r\n    font-size: 1.8rem;\r\n    background-color: $elements__background;\r\n    width: 100%;\r\n    box-shadow: none;\r\n    border: none;\r\n    border-bottom: 1px solid $color__text;\r\n    outline: none;\r\n    border-radius: 0px;\r\n    height: auto;\r\n    &:hover,&:focus,&:active,&:visited{\r\n      background-color: $elements__background;\r\n      box-shadow: none;\r\n      outline: none;\r\n    }\r\n    &:focus, &:active, &:visited{\r\n      border-bottom: 1px solid $color__clickable;\r\n    }\r\n}\r\n\r\n// TextArea style\r\n\r\n.textarea_style{\r\n    background-color: $elements__background;\r\n    font-size: 1.17rem;\r\n    width: 100%;\r\n    box-shadow: none;\r\n    border: none;\r\n    border-left: 1px solid $color__text;\r\n    outline: none;\r\n    border-radius: 0px;\r\n    height: auto;\r\n    &:hover,&:focus,&:active,&:visited{\r\n        background-color: $elements__background;\r\n        box-shadow: none;\r\n        outline: none;\r\n      }\r\n    &:focus, &:active, &:visited{\r\n        border-left: 1px solid $color__clickable;\r\n    }\r\n}\r\n\r\n.elements_box{\r\n    background-color: $elements__background;\r\n    border-radius: 20px;\r\n    border: 1px solid $elements__box_border_color;\r\n}\r\n\r\n.element_opacity{\r\n    opacity: 1;\r\n    transition: 0.5s;\r\n    &:hover{\r\n        opacity: 0.75;\r\n        color: $color__text;\r\n    }\r\n}\r\n\r\n.buttons_style{\r\n    padding: 8px;\r\n    background-color: $color__clickable;\r\n    border-radius: 5px;\r\n    width: auto;\r\n    text-decoration: none !important;\r\n    color: $buttons__color;\r\n    opacity: 1;\r\n    min-width: 100px;\r\n    transition: 0.71s;\r\n    &:hover{\r\n        background-color: $color__clickable;\r\n        color: $buttons__color;\r\n        opacity: 0.84;\r\n    }\r\n    &:hover,&:focus,&:visited,&:active{\r\n        text-decoration: none;\r\n    }\r\n}\r\n\r\n// Text and Font for all texts.\r\n.content_text_font_size{\r\n    line-height: 1.8rem;\r\n    font-size: 1.12rem;\r\n    // p{\r\n        // font-size: 1.12rem;\r\n    // }\r\n}\r\n\r\n// Scrollbar modern\r\n.scrollbar_modern{\r\n    $boder: 10px;\r\n    $size: 7px;\r\n    /* Custom scrollbar */\r\n    ::-webkit-scrollbar {\r\n      width: $size;\r\n      height: $size;\r\n      margin-right: 9px;\r\n      background: $background__full;\r\n    }\r\n  \r\n    /* Track - Bg */\r\n    ::-webkit-scrollbar-track {\r\n      -webkit-box-shadow: inset 0 0 6px transparent;\r\n      -webkit-border-radius: $boder;\r\n      border-radius: $boder;\r\n    }\r\n  \r\n    /* Handle */\r\n    ::-webkit-scrollbar-thumb {\r\n      -webkit-border-radius: $boder;\r\n      border-radius: $boder;\r\n      background: $color__clickable;\r\n      -webkit-box-shadow: inset 0 0 6px $color__clickable;\r\n    }\r\n    ::-webkit-scrollbar-thumb:window-inactive {\r\n    background: $color__clickable;\r\n    }\r\n  }\r\n\r\n.animation {\r\n    animation-name: fade;\r\n    animation-duration: 500ms;\r\n    &__move{\r\n        animation-name: move;\r\n        animation-duration: 500ms;\r\n        animation-delay: 250ms;\r\n        animation-fill-mode: backwards;\r\n    }\r\n    &__down{\r\n        animation-name: down;\r\n        animation-duration: 500ms;\r\n    }\r\n    &__pulse{\r\n        animation: pulse 1s linear;\r\n    }\r\n    &__sidebar-title{\r\n        animation: move 500ms;\r\n        animation-delay: 250ms;\r\n        animation-fill-mode: backwards;\r\n    } \r\n    &__sidebar-menu{\r\n        animation: move 600ms;\r\n        animation-delay: 290ms;\r\n        animation-fill-mode: backwards;\r\n    }\r\n    &__content{\r\n        animation: move_invert 670ms;\r\n        animation-delay: 310ms;\r\n        animation-fill-mode: backwards;\r\n    }\r\n    &__terminal{\r\n        animation: fade 670ms;\r\n        animation-delay: 310ms;\r\n        animation-fill-mode: backwards;\r\n    }\r\n}\r\n",
		"@keyframes fade {\r\n    from{\r\n        opacity: 0;\r\n        transform: scale(0.9);\r\n    }to{\r\n        opacity: 1;\r\n        transform: scale(1);\r\n    }\r\n}\r\n\r\n@keyframes move {\r\n    from{\r\n        opacity: 0;\r\n        transform: translateX(-35%)\r\n    }to{\r\n        opacity: 1;\r\n        transform: translateX(0%)\r\n    }\r\n}\r\n\r\n@keyframes move_invert {\r\n    from{\r\n        opacity: 0;\r\n        transform: translateX(35%)\r\n    }to{\r\n        opacity: 1;\r\n        transform: translateX(0%)\r\n    }\r\n}\r\n\r\n@keyframes down {\r\n    from{\r\n        opacity: 0;\r\n        transform: rotateY(-45%);\r\n    }to{\r\n        opacity: 1;\r\n        transform: rotateY(0%);\r\n    }\r\n}\r\n\r\n@keyframes pulse{\r\n  0% {\r\n    box-shadow: 0 0 0 0px $keyframe__pulse_color_primary;\r\n  }\r\n  100% {\r\n    box-shadow: 0 0 0 35px $keyframe__pulse_color_secondary;\r\n  }\r\n}\r\n",
		"/* \r\n––––––––––––––––––––––––––––––––––––––––––––––––––  */\r\n\r\n@import \"table\";\r\n@import \"blockquote\";\r\n@import \"toc\";",
		"/* \r\n––––––––––––––––––––––––––––––––––––––––––––––––––  */\r\n\r\ntable{\r\n    margin: 2% 0%;\r\n    width: 100%;\r\n    thead{\r\n      tr{ \r\n        th{\r\n          padding: 5px;\r\n          border: 1px solid $table__thead_th_border;\r\n          color: $table__thead_th_color;\r\n          background-color: $table__thead_th_background;\r\n        }\r\n      }\r\n    }\r\n    tbody{\r\n      background-color: $table__tbody_td_background;\r\n      tr{\r\n        td{\r\n          padding: 5px;\r\n          border: 1px solid $table__tbody_td_border;\r\n          color: $table__tbody_td_color;\r\n          background-color: $table__tbody_td_background;\r\n          code{\r\n            background-color: transparent;\r\n          }\r\n        }\r\n      }\r\n    }\r\n  }",
		"/* \r\n––––––––––––––––––––––––––––––––––––––––––––––––––  */\r\n\r\nblockquote{\r\n    border: none !important;\r\n    background-color: $blockquote__background;\r\n    border-left: 5px solid $color__clickable !important;\r\n    padding: 10px 10px 0px 10px;\r\n    border-top-left-radius: 0px;\r\n    border-bottom-left-radius: 0px;\r\n    border-bottom-right-radius: 0px;\r\n    p{\r\n      padding-bottom: 10px;\r\n    }\r\n  }",
		"#markdown-toc{\r\n    margin-bottom: 100px;\r\n    &:before{\r\n      content: attr(data-content);\r\n      font-weight: bold;\r\n      font-size: 1.8rem;\r\n    }\r\n  }",
		"/* \r\n––––––––––––––––––––––––––––––––––––––––––––––––––  */\r\n\r\n@import \"default\";\r\n@import \"hello\";\r\n@import \"page\";\r\n@import \"postlist\";\r\n@import \"post\";\r\n@import \"contact\";\r\n@import \"search\";\r\n@import \"tags\";\r\n@import \"error\";\r\n@import \"taglist\";\r\n@import \"resume\";",
		".layout_default{\r\n    // z-index: 2;\r\n}\r\n",
		".layout_hello{\r\n    @extend .elements_box;\r\n    @extend .content_text_font_size;\r\n    // line-height: 1.8rem;\r\n    // p{font-size: 1.12rem;}\r\n\r\n    // 1920x1080\r\n    @media (min-width: 1920px) {\r\n        margin-top: 194px;\r\n    }\r\n}",
		".layout_page{\r\n    @extend .content_text_font_size;\r\n    &__header, &__content{\r\n        @extend .elements_box;\r\n    }\r\n}",
		".layout_postlist{\r\n\r\n    &__header, &__content{\r\n        @extend .elements_box;\r\n        @extend .content_text_font_size;\r\n    }\r\n    &__comments{\r\n        background-color: $texts__background;\r\n        font-size: 0.97rem;\r\n        color: $color__text;\r\n        &-count{}\r\n    }\r\n    &__time{\r\n        background-color: $texts__background;\r\n        opacity: 0.77;\r\n        color: $color__text;\r\n        border-radius: 5px;\r\n    }\r\n    &__excerpted{\r\n        background-color: $texts__background;\r\n        border-radius: 5px;\r\n        line-height: 1.8rem;\r\n    }\r\n    &__comments{\r\n        .fa-comments{\r\n            margin: 0px 4px;\r\n        }\r\n        .disqus-comment-count{\r\n            color: $color__clickable;\r\n        }\r\n    }\r\n    &__pagination{\r\n        &-newer{\r\n            @extend .buttons_style;\r\n            border-radius: 0px;\r\n            border: 1px solid $color__clickable;\r\n            &:hover{\r\n                border: 1px solid $color__clickable;\r\n            }\r\n        }\r\n        &-counter{\r\n            color: $color__clickable;\r\n            background-color: $elements__background;\r\n            border: 1px solid;\r\n            &:hover{\r\n                color: $color__clickable;\r\n                background-color: $elements__background;\r\n                border: 1px solid;\r\n            }\r\n        }\r\n        &-older{\r\n            @extend .buttons_style;\r\n            border-radius: 0px;\r\n            border: 1px solid $color__clickable;\r\n            &:hover{\r\n                border: 1px solid $color__clickable;\r\n            }\r\n        }\r\n    }\r\n}",
		".layout_post{\r\n    @extend .content_text_font_size;\r\n    &__header, &__content, &__footer, &__disqus{\r\n        @extend .elements_box;\r\n    }\r\n    &__comments{\r\n        background-color: $texts__background;\r\n        color: $color__text;\r\n        font-size: 1rem;\r\n        &-count{}\r\n    }\r\n    &__share-link {\r\n\r\n        &--text{\r\n            visibility: hidden;\r\n            font-size: 14px;\r\n            position: absolute;\r\n            top: 65px;\r\n            left: 50%;\r\n            -moz-transform: translate(-50%, 0%);\r\n            -o-transform: translate(-50%, 0%);\r\n            -ms-transform: translate(-50%, 0%);\r\n            -webkit-transform: translate(-50%, 0%);\r\n            transform: translate(-50%, 0%);\r\n        }\r\n\r\n        &:hover{\r\n            .layout_post__share-link--text {\r\n              visibility: visible;\r\n            }\r\n        }\r\n        \r\n    }\r\n    &__share-icon{\r\n        font-size: 50px;\r\n        margin: 15px 0px;\r\n    }\r\n    &__author{\r\n        &-img{\r\n            border-radius: 50%;\r\n            border: 1px solid $color__text;\r\n            padding: 3px;\r\n        }\r\n    }\r\n\r\n}",
		".layout_contact{\r\n    @extend .content_text_font_size;\r\n    \r\n    &__header, &__form, &__note{\r\n        @extend .elements_box;\r\n    }\r\n    &__input{\r\n        @extend .inputs_style;\r\n        font-size: 1.3rem;\r\n    }\r\n    &__textarea{\r\n        @extend .textarea_style;\r\n    }\r\n    &__form-button{\r\n        @extend .buttons_style;\r\n    }\r\n}",
		"/* Stylesheets for layout Search\r\n––––––––––––––––––––––––––––––––––––––––––––––––––  */\r\n\r\n\r\n.layout-search{\r\n    @extend .elements_box;\r\n    @extend .content_text_font_size;\r\n  &__form{\r\n    border-radius: 0px;\r\n    height: auto;\r\n    &-group{\r\n      &:hover,&:focus,&:active,&:visited{\r\n        box-shadow: none !important;\r\n        border: none;\r\n        outline: none;\r\n      }\r\n    }\r\n  }\r\n  &__description{\r\n    font-size: 1.2rem;\r\n  }\r\n  &__shellicon{\r\n    font-size: 1.8rem;\r\n    margin-top: 1rem;\r\n  }\r\n  &__input{\r\n    @extend .inputs_style;\r\n    @media (min-width: 300px) and (max-width: 992px) {\r\n      font-size: 1.2rem !important;\r\n    }\r\n  }\r\n  &__btn-clear{\r\n    @extend .buttons_style;\r\n    &:hover,&:focus,&:active,&:visited{\r\n      text-decoration: none;\r\n    }\r\n  }\r\n  &__data{\r\n    list-style: none;\r\n    margin: 15px 0px;\r\n    font-size: 1.3rem;\r\n    li{\r\n      margin: 15px 0px;\r\n    }\r\n    transition: 0.9s;\r\n    a{\r\n      transition: 0.9s;\r\n      &:hover{\r\n        transition: 0.9s;\r\n        .layout-search__data__entry-date{\r\n          transition: 0.9s;\r\n          background-color: $color__text;\r\n        }\r\n      }\r\n    }\r\n    &__entry-date{\r\n      font-size: 0.9rem;\r\n      padding: 5px;\r\n      background-color: $color__clickable;\r\n      margin-left: 10px;\r\n      border-radius: 0px;\r\n      color: #fff;\r\n    }\r\n    &__not-search{\r\n      padding: 15px 0;\r\n      color: red;\r\n      font-size: 1.7rem;\r\n    }\r\n  }\r\n}\r\n",
		".layout_tag{\r\n    &__header, &__content{\r\n    \t@extend .content_text_font_size;\r\n        @extend .elements_box;\r\n    }\r\n    &__time{\r\n        background-color: $texts__background;\r\n        opacity: 0.77;\r\n        color: $color__text;\r\n        border-radius: 5px;\r\n    }\r\n    &__comments{\r\n        &-count{}\r\n    }\r\n}",
		".layout_error{\r\n    &__header, &__content{\r\n        @extend .elements_box;\r\n    }\r\n    &__icon{\r\n        font-size: 8rem;\r\n        color: red;\r\n    }\r\n    &__content{\r\n        @extend .content_text_font_size;\r\n    }\r\n}",
