		"/*\r\n––––––––––––––––––––––––––––––––––––––––––––––––––  */\r\n\r\n@import \"sidebar\";\r\n@import \"content\";\r\n@import \"footer\";\r\n@import \"terminal\";\r\n@import \"socials_networks\";\r\n@import \"email_successfully_sent\";\r\n@import \"email_failed_sent\";\r\n@import \"affiliates\";\r\n\r\n// VVFolded\r\n@import \"vvfolded\";",
		".sidebar{\r\n    background-color: $background__full;\r\n    &__avatar_flip{\r\n        // position: relative;\r\n        perspective: 1000;\r\n        margin: 10px auto;\r\n        width: 165px;\r\n        height: 165px;\r\n        &-card{\r\n            transform-style: preserve-3d;\r\n            transition: all 1.0s linear;\r\n        }        \r\n        &-face{\r\n            position: absolute;\r\n            backface-visibility: hidden;\r\n        }\r\n    }\r\n    .sidebar__avatar_flip-back.sidebar__avatar_flip-face{\r\n        display: block;\r\n        transform: rotateY(180deg);   \r\n    }\r\n    &__avatar_flip, &__avatar_noflip{\r\n        .image_avatar{\r\n            width: 165px;\r\n            height: 165px;\r\n        }\r\n    }\r\n    &__title{\r\n        font-family: $font-family__secondary;\r\n        background-color: $elements__background;\r\n        border-radius: 20px;\r\n        color: $color__clickable;\r\n        border: 1px solid $elements__box_border_color;\r\n    }\r\n    &__menu{\r\n        font-family: $font-family__secondary;\r\n        background-color: $elements__background;\r\n        border-radius: 20px;\r\n        border: 1px solid $elements__box_border_color;\r\n        &-title{\r\n          font-size: 1.3rem;\r\n        }\r\n        &-link{\r\n          font-size: 1.3rem;\r\n          line-height: 1.64rem;\r\n          &:hover{\r\n            text-decoration: underline;\r\n          }\r\n        }\r\n    }\r\n}\r\n",
		".layout_default{\r\n    .content{\r\n        &__wrapper{}\r\n    }\r\n}\r\n",
		"/* Stylesheets for include Footer\r\n––––––––––––––––––––––––––––––––––––––––––––––––––  */\r\n\r\n.footer{\r\n  background-color: $footer__bg;\r\n  font-size: 0.8rem;\r\n  color: $color__text;\r\n}\r\n\r\n.scrolltop{\r\n  color: $color__text;\r\n  font-size: 3rem;\r\n  &__button{\r\n    font-size: 3rem !important;\r\n  }\r\n}\r\n",
		"/* \r\n––––––––––––––––––––––––––––––––––––––––––––––––––  */\r\n\r\n.intro{\r\n    &__terminal{\r\n        font-family: $font-family__terminal;\r\n        // @media (max-width: 768px) {\r\n        // display: none;\r\n        // }\r\n        margin-top: 2%;\r\n        -webkit-box-shadow: 0px 0px 56px -3px $terminal__shadow_color;\r\n        -moz-box-shadow: 0px 0px 56px -3px $terminal__shadow_color;\r\n        box-shadow: 0px 0px 56px -3px $terminal__shadow_color;\r\n        border-radius: 7px 7px 5px 5px;\r\n\r\n        /* .intro__terminal .header */\r\n        .header{\r\n        background: #000;\r\n        border-radius: 7px 7px 0 0;\r\n        padding-left: 10px;\r\n        color: #fff;\r\n\r\n        /* .header__btn */\r\n        &__btn{\r\n            float: left;\r\n            padding: 0;\r\n            width: 12px;\r\n            height: 12px;\r\n            margin: 8px 5px 0 0;\r\n            display: inline-block;\r\n            border-radius: 50%;\r\n\r\n            /* .header__btn--green */\r\n            &--green{\r\n            background-color: #3BB662;\r\n            } /* END - .header__btn--green */\r\n\r\n            /* .header__btn--yellow */\r\n            &--yellow{\r\n            background-color: #ffe609;\r\n            } /* END - .header__btn--yellow */\r\n\r\n            /* .header__btn--red */\r\n            &--red{\r\n            background-color: #ec4d3b;\r\n            } /* END - .header__btn--red */\r\n\r\n        } /* END - .header__btn */\r\n\r\n        } /* END - .intro__terminal .header */\r\n\r\n\r\n        /* .intro__terminal .title */\r\n        .title{\r\n        font-size: 9pt !important;\r\n        text-align: center;\r\n        padding: 3px 0px;\r\n\r\n        /* .intro__terminal .title__text */\r\n        &__text{\r\n            margin-left: -56px;\r\n            color: #fff;\r\n        } /* END -.intro__terminal .title__text */\r\n\r\n        } /* END - .intro__terminal .titl */\r\n\r\n\r\n        /* .intro__terminal .body */\r\n        .body{\r\n        color: #3bff1a;\r\n        background: #000;\r\n        padding: 10px;\r\n        box-sizing: border-box;\r\n        width: 100%;\r\n        overflow: auto;\r\n        font-weight: 400;\r\n        min-height: 250px;\r\n        border-radius: 0 0 5px 5px;\r\n        line-height: 1.3rem;\r\n        font-size: 12pt !important;\r\n        p{\r\n            a{\r\n                color: #3BB662;\r\n            }\r\n        }\r\n\r\n        /* .intro__terminal .body__output */\r\n        &__output{\r\n            min-height: 21px !important;\r\n            span{\r\n                display: inline;\r\n                min-height: 21px !important;\r\n            }\r\n            &:after {\r\n            content:\" _\";\r\n            opacity: 0;\r\n            color: white;\r\n            animation: cursor 1s infinite;\r\n            min-height: 21px !important;\r\n            }\r\n            &__user{\r\n                color: magenta;\r\n            }\r\n            &__at{\r\n                color: white;\r\n            }\r\n            &__os{\r\n                color: yellow;\r\n            }\r\n            &__dir{\r\n                color: cyan;\r\n            }\r\n        } /* END - .intro__terminal .body__output */\r\n\r\n        } /* END - .intro__terminal .body */\r\n    } /* END - .intro__terminal */\r\n}",
		".socials_network{\r\n    &__header, &__body{\r\n        background-color: $background__full !important;\r\n        border: 1px solid $color__text;\r\n    }\r\n    &__icon{\r\n        font-size: 3.5rem;\r\n    }\r\n    &__close{\r\n        color: $color__text;\r\n        &:hover{\r\n            color: $color__text;\r\n        }\r\n    }\r\n}",
		".email_successfully_sent{\r\n    &__content{\r\n        background-color: $background__full;\r\n    }\r\n    &__header{}\r\n    &__body{}\r\n    &__icon{\r\n        font-size: 7rem;\r\n        color: #24aa20;\r\n        .el_icon{\r\n            border-radius: 50%;\r\n            padding: 20px;\r\n            background-color: #fff;\r\n        }\r\n    }\r\n    &__message_header{\r\n        h4{\r\n            font-size: 1.67rem;\r\n            color: $color__text;\r\n        }\r\n    }\r\n    &__message_body{\r\n        p{\r\n            font-size: 1.43rem;\r\n        }\r\n    }\r\n}",
		".email_failed_sent{\r\n    &__content{\r\n        background-color: $background__full;\r\n    }\r\n    &__header{}\r\n    &__body{}\r\n    &__icon{\r\n        font-size: 7rem;\r\n        color: #e61923;\r\n        .el_icon{\r\n            border-radius: 50%;\r\n            padding: 20px;\r\n            background-color: #fff;\r\n        }\r\n    }\r\n    &__message_header{\r\n        h4{\r\n            font-size: 1.67rem;\r\n            color: $color__text;\r\n        }\r\n    }\r\n    &__message_body{\r\n        p{\r\n            font-size: 1.43rem;\r\n        }\r\n    }\r\n}",
