		"@keyframes avatar_vvfolded1{\r\n    0% {\r\n        fill: #ffe609;\r\n    }\r\n    100% {\r\n        // fill: #3BB662;\r\n        fill: #FFF;\r\n    }\r\n}\r\n\r\n@keyframes avatar_vvfolded2{\r\n    0% {\r\n        fill: #ffe609;\r\n    }\r\n    100% {\r\n        // fill: #3BB662;\r\n        fill: #FFF;\r\n    }\r\n}\r\n\r\n.animation{\r\n    &__avatar_vvfolded1{\r\n        animation: avatar_vvfolded1 2200ms infinite;\r\n        animation-delay: 500ms;\r\n    }\r\n    &__avatar_vvfolded2{\r\n        animation: avatar_vvfolded2 2200ms infinite;\r\n        animation-delay: 500ms;\r\n    }\r\n}\r\n.sidebar{\r\n    &__avatar_noflip, &__avatar_flip{\r\n        .svg_vvfolded{\r\n            width: 165px;\r\n            height: 165px;\r\n            &__vvfolded1{\r\n                @extend .animation__avatar_vvfolded1;\r\n            }\r\n            &__vvfolded2{\r\n                @extend .animation__avatar_vvfolded2;\r\n            }\r\n            &__background{}\r\n        }\r\n    }\r\n}",
		"\r\n.gist{\r\n    .gist-data{\r\n        background-color: $gist__background !important;\r\n        color: $gist__code_color !important;\r\n    }\r\n    .gist-file{\r\n        border-color: $gist__border !important;\r\n    }\r\n    .blob-code, .blob-num{\r\n        color: $gist__code_color !important;\r\n        border: 0.1rem solid $gist__background !important;\r\n        background: $gist__background !important;\r\n    }\r\n    .js-line-number{\r\n        background: $gist__ln_background !important;\r\n        color: $gist__ln_color !important;\r\n    }\r\n    .gist-meta{\r\n        background-color: $gist__background !important;\r\n        color: $gist__meta_color !important;\r\n        /* Link meta */\r\n        a{\r\n            color: $gist__meta_link_color !important;\r\n        }\r\n    }\r\n  \r\n    /* Comments */\r\n    .pl-c{\r\n    color: $gist__comment_color !important;\r\n    }\r\n  \r\n    /* Function */\r\n    .pl-k, tbody tr:first-child .blob-code, tbody tr:last-child .blob-code{\r\n    color: $gist__function_color !important;\r\n    }\r\n  \r\n    /* Function Name */\r\n    .pl-en{\r\n    color: $gist__fn_color !important;\r\n    }\r\n  \r\n    /* Function Method */\r\n    .pl-c1{\r\n    color: $gist__fn_color !important;\r\n    }\r\n    /* \"'s around Strings */\r\n    .pl-pds{\r\n    color: $gist__string_color !important;\r\n    }\r\n  \r\n    /* Strings */\r\n    .pl-s{\r\n    color: $gist__string_color !important;\r\n    }\r\n  \r\n    .pl-smi{\r\n        color: $gist__var_color !important;\r\n    }\r\n  }",
		"/* \r\n––––––––––––––––––––––––––––––––––––––––––––––––––  */\r\n@import \"resume\";",
		"/* Stylesheets for print page Resume\r\n---------------------------------------------------------------*/\r\n\r\n@media print {\r\n  .sidebar,.footer, .scrolltop, #markdown-toc, .remove-printer{\r\n    display: none !important;\r\n  }\r\n  .scrolltop__button{\r\n    display: none !important;\r\n  }\r\n  .layout_default__content{\r\n    border: none !important;\r\n  }\r\n  .layout_resume{\r\n    border: none !important;\r\n    line-height: 1.5rem;\r\n    &__header, &__excerpt{\r\n      display: none;\r\n    }\r\n    &__photo_cv{\r\n      display: block !important;\r\n    }\r\n    &__content{\r\n      color: #000;\r\n      border: none !important;\r\n      a,code{\r\n        color: #000;\r\n      }\r\n      .emoji{\r\n      \tdisplay: none !important;\r\n      }\r\n      hr{\r\n        border-top: 1px solid #000;\r\n      }\r\n      /* Avoid printing hrefs when this class is applied */\r\n      a[href]:after {\r\n        content: none !important;\r\n      }\r\n      .badge__plugin{\r\n        box-shadow: none !important;\r\n        border: 1px solid #000 !important;\r\n        color: #000 !important;\r\n        background-color: white !important;\r\n        font-weight: bold;\r\n      }\r\n      blockquote{\r\n        border: none;\r\n        background-color: transparent;\r\n      }\r\n    }\r\n  }\r\n}\r\n",
